186	  display: "flex",
187	  flexWrap: "wrap",
188	  alignItems: "center",
189	  gap: "var(--space-sm)",
190	};
191	
192	const commentAuthorStyle: React.CSSProperties = {
193	  fontSize: "0.85rem",
194	  fontWeight: 600,
195	};
196	
197	const commentMetaStyle: React.CSSProperties = {
198	  color: "var(--color-text-muted)",
199	  fontSize: "0.75rem",
200	};
